    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);         // align the starting addresss

    const long rhs_cols = ker_dim_y * ker_dim_x * ker_ch;
    const long rhs_cols_aligned = nn_align((long)rhs_cols, align_byte);

    // calculate the weight contribution
    const int8_t *pWt = ker_weight;
    const long cst_one = 0x01010101;

    for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
    {
        long sum = 0;
        long rhs_cols2 = rhs_cols;

        while (rhs_cols2 >= SIMD_NUM_Q7)
        {
            suni_t wt_s8 = simd_load_8((s8_t*)pWt, 0);
            sum = NDS_DSP_SMAQA(sum, wt_s8.l0, cst_one);
            rhs_cols2 -= SIMD_NUM_Q7;
            pWt += SIMD_NUM_Q7;
        }

        // rest loop
        while (rhs_cols2 > 0)
        {
            sum += *pWt;
            rhs_cols2--;
            pWt++;
        }

        sum *= in_offset;

        if (bias != NULL)
        {
            sum += bias[cur_out_ch];
        }
        contri_buf[cur_out_ch] = sum;
    }

    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *two_column_buf2 = (int8_t *)two_column_buf;
        const int8_t *pKer_wt = &ker_weight[0];
        const int32_t *pOut_scale = &out_scale[0];
        const int32_t *pOut_shift = &out_shift[0];
        const int32_t *pContri_buf = &contri_buf[0];

        /* This part implements the im2col function */
        for (long cur_group = 0; cur_group < groups; cur_group++)
        {
            int8_t *out = out_tensor + cur_group * out_ch_per_group;
            for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
            {
                for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
                {
                    for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + (ker_dim_y - 1) * dilation_y + 1; cur_ker_y += dilation_y)
                    {
                        for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + (ker_dim_x - 1) * dilation_x + 1; cur_ker_x += dilation_x)
                        {
                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
                            {
                                nn_set_val_s8(two_column_buf2, -in_offset, ker_ch);
                            }
                            else
                            {
                                nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch + cur_group * ker_ch,
                                                two_column_buf2,
                                                ker_ch * sizeof(*in_tensor));
                            }
                            two_column_buf2 += ker_ch;
                        }
                    }

                    /* Computation is filed for every 2 columns */
                    if (two_column_buf2 == (int8_t *)in_tmp_buf + 2 * ker_ch * ker_dim_y * ker_dim_x)
                    {
                        out = nn_mat_mult_kernel_s8_offset_v3(pKer_wt,
                                                              two_column_buf,
                                                              out_ch_per_group,
                                                              out_tensor_ch,
                                                              pOut_shift,
                                                              pOut_scale,
                                                              in_offset,
                                                              out_offset,
                                                              act_min,
                                                              act_max,
                                                              rhs_cols,
                                                              rhs_cols_aligned,
                                                              pContri_buf,
                                                              out);

                        /* counter reset */
                        two_column_buf2 = (int8_t *)two_column_buf;
                    }
                }
            }

            /* left-over because odd number of out_tensor pixels */
            if (two_column_buf2 != (int8_t *)two_column_buf)
            {
                const int8_t *pKer_wt2 = pKer_wt;
                const int32_t *pOut_scale2 = pOut_scale;
                const int32_t *pOut_shift2 = pOut_shift;
                const int32_t *pContri_buf2 = pContri_buf;

                for (long cur_out_ch_in_group = 0; cur_out_ch_in_group < out_ch_per_group; cur_out_ch_in_group++)
                {
                    const int8_t *pIn = (int8_t *)two_column_buf;
                    long acc = 0;
                    long rhs_cols2 = rhs_cols;

                    while (rhs_cols2 >= SIMD_NUM_Q7)
                    {
                        suni_t in_val = simd_load_8((s8_t*)pIn, 0);
                        suni_t wt_val = simd_load_8((s8_t*)pKer_wt2, 0);
                        acc = NDS_DSP_SMAQA(acc, in_val.l0, wt_val.l0);
                        pIn += SIMD_NUM_Q7;
                        pKer_wt2 += SIMD_NUM_Q7;
                        rhs_cols2 -= SIMD_NUM_Q7;
                    }

                    // rest loop
                    while (rhs_cols2 > 0)
                    {
                        acc += *pIn * *pKer_wt2;
                        pIn++;
                        pKer_wt2++;
                        rhs_cols2--;
                    }

                    // add contribution back
                    acc += *pContri_buf2;

                    acc = nn_requantize(acc, *pOut_scale2, *pOut_shift2);
                    acc += out_offset;
                    acc = MAX(acc, act_min);
                    acc = MIN(acc, act_max);
                    *out++ = (int8_t)acc;

                    pContri_buf2++;
                    pOut_scale2++;
                    pOut_shift2++;
                }
                /* counter reset */
                two_column_buf2 = (int8_t *)two_column_buf;
            }
            pKer_wt += out_ch_per_group * rhs_cols;
            pOut_scale += out_ch_per_group;
            pOut_shift += out_ch_per_group;
            pContri_buf += out_ch_per_group;
        }
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#else
    (void)in_tmp_buf;
    const int32_t groups = in_tensor_ch / ker_ch;
    const int32_t out_ch_per_group = out_tensor_ch / groups;

    if (in_tensor_ch % groups != 0 || out_tensor_ch % groups != 0)
    {
        return -1;
    }

    for (int32_t i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        for (int32_t i_group = 0; i_group < groups; i_group++)
        {
            for (int32_t i_out_ch_in_group = 0; i_out_ch_in_group < out_ch_per_group; i_out_ch_in_group++)
            {
                for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
                {
                    for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
                    {
                        const int32_t base_idx_y = stride_y * i_out_y - pad_y;
                        const int32_t base_idx_x = stride_x * i_out_x - pad_x;
                        const int32_t start_y_max = (-base_idx_y + dilation_y - 1) / dilation_y;
                        const int32_t start_x_max = (-base_idx_x + dilation_x - 1) / dilation_x;
                        const int32_t ker_y_start = MAX(0, start_y_max);
                        const int32_t ker_x_start = MAX(0, start_x_max);
                        const int32_t end_min_y = (in_tensor_dim_y - base_idx_y + dilation_y - 1) / dilation_y;
                        const int32_t end_min_x = (in_tensor_dim_x - base_idx_x + dilation_x - 1) / dilation_x;
                        const int32_t ker_y_end = MIN(ker_dim_y, end_min_y);
                        const int32_t ker_x_end = MIN(ker_dim_x, end_min_x);
                        const int32_t i_out_ch = i_group * out_ch_per_group + i_out_ch_in_group;

                        int32_t conv_out = 0;
                        if (bias)
                        {
                            conv_out = bias[i_out_ch];
                        }

                        for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
                        {
                            for (int32_t i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                            {
                                const int32_t in_row = base_idx_y + dilation_y * i_ker_y;
                                const int32_t in_col = base_idx_x + dilation_x * i_ker_x;
                                for (int32_t i_ker_ch = 0; i_ker_ch < ker_ch; i_ker_ch++)
                                {
                                    int32_t i_input_ch = i_group * ker_ch + i_ker_ch;
                                    int32_t in_idx = (in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_input_ch;
                                    int32_t wt_idx = i_out_ch * ker_ch * ker_dim_y * ker_dim_x + (i_ker_y * ker_dim_x + i_ker_x) * ker_ch + i_ker_ch;
                                    int32_t in_val = in_tensor[in_idx] + in_offset;
                                    int32_t wt_val = ker_weight[wt_idx];
                                    conv_out += in_val * wt_val;
                                }
                            }
                        }
                        conv_out = nn_requantize(conv_out, out_scale[i_out_ch], out_shift[i_out_ch]);
                        conv_out += out_offset;
                        conv_out = MAX(conv_out, act_min);
                        conv_out = MIN(conv_out, act_max);
                        out_tensor[i_out_ch + (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch] = (int8_t)conv_out;
                    }
                }
            }
        }
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

int32_t riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any_dilated_get_buffer_size(const uint16_t ker_ch,
                                                                         const uint16_t ker_dim_x,
                                                                         const uint16_t ker_dim_y,
                                                                         const uint16_t out_tensor_ch)
{
#if defined(ENA_DSP_ISA_V5) || (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD))
    const long align_byte = sizeof(long);

    // four col buffer (supports 4-pixel batching for groups==1 unroll4 path)
    int32_t buf_size = 4 * ker_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for extra contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning

    return buf_size;
#else
    (void)ker_ch;
    (void)ker_dim_x;
    (void)ker_dim_y;
    (void)out_tensor_ch;
    return 0;
#endif
}

