1092→                        suni_t in_val = simd_load_8((s8_t*)pIn, 0);
1093→                        suni_t wt_val = simd_load_8((s8_t*)pKer_wt2, 0);
1094→                        acc = NDS_DSP_SMAQA(acc, in_val.l0, wt_val.l0);
1095→                        pIn += SIMD_NUM_Q7;
1096→                        pKer_wt2 += SIMD_NUM_Q7;
1097→                        rhs_cols2 -= SIMD_NUM_Q7;
1098→                    }
1099→
1100→                    // rest loop
1101→                    while (rhs_cols2 > 0)
1102→                    {
1103→                        acc += *pIn * *pKer_wt2;
1104→                        pIn++;
1105→                        pKer_wt2++;
1106→                        rhs_cols2--;
1107→                    }
1108→
1109→                    // add contribution back
1110→                    acc += *pContri_buf2;
1111→
1112→                    acc = nn_requantize(acc, *pOut_scale2, *pOut_shift2);
1113→                    acc += out_offset;
1114→                    acc = MAX(acc, act_min);
1115→                    acc = MIN(acc, act_max);
1116→                    *out++ = (int8_t)acc;
1117→
1118→                    pContri_buf2++;
1119→                    pOut_scale2++;
1120→                    pOut_shift2++;
1121→                }
1122→                /* counter reset */
1123→                two_column_buf2 = (int8_t *)two_column_buf;
1124→            }
1125→            pKer_wt += out_ch_per_group * rhs_cols;
1126→            pOut_scale += out_ch_per_group;
1127→            pOut_shift += out_ch_per_group;
1128→            pContri_buf += out_ch_per_group;
1129→        }
1130→        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
1131→        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
1132→    }
1133→#else
1134→    (void)in_tmp_buf;
1135→    const int32_t groups = in_tensor_ch / ker_ch;
1136→    const int32_t out_ch_per_group = out_tensor_ch / groups;
1137→
1138→    if (in_tensor_ch % groups != 0 || out_tensor_ch % groups != 0)
1139→    {
1140→        return -1;
1141→    }
1142→
1143→    for (int32_t i_batch = 0; i_batch < in_tensor_batch; i_batch++)
1144→    {
1145→        for (int32_t i_group = 0; i_group < groups; i_group++)
1146→        {
1147→            for (int32_t i_out_ch_in_group = 0; i_out_ch_in_group < out_ch_per_group; i_out_ch_in_group++)
1148→            {
1149→                for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
1150→                {
1151→                    for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
1152→                    {
1153→                        const int32_t base_idx_y = stride_y * i_out_y - pad_y;
1154→                        const int32_t base_idx_x = stride_x * i_out_x - pad_x;
1155→                        const int32_t start_y_max = (-base_idx_y + dilation_y - 1) / dilation_y;
1156→                        const int32_t start_x_max = (-base_idx_x + dilation_x - 1) / dilation_x;
1157→                        const int32_t ker_y_start = MAX(0, start_y_max);
1158→                        const int32_t ker_x_start = MAX(0, start_x_max);
1159→                        const int32_t end_min_y = (in_tensor_dim_y - base_idx_y + dilation_y - 1) / dilation_y;
1160→                        const int32_t end_min_x = (in_tensor_dim_x - base_idx_x + dilation_x - 1) / dilation_x;
1161→                        const int32_t ker_y_end = MIN(ker_dim_y, end_min_y);
1162→                        const int32_t ker_x_end = MIN(ker_dim_x, end_min_x);
1163→                        const int32_t i_out_ch = i_group * out_ch_per_group + i_out_ch_in_group;
1164→
1165→                        int32_t conv_out = 0;
1166→                        if (bias)
1167→                        {
1168→                            conv_out = bias[i_out_ch];
1169→                        }
1170→
1171→                        for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
1172→                        {
1173→                            for (int32_t i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
1174→                            {
1175→                                const int32_t in_row = base_idx_y + dilation_y * i_ker_y;
1176→                                const int32_t in_col = base_idx_x + dilation_x * i_ker_x;
1177→                                for (int32_t i_ker_ch = 0; i_ker_ch < ker_ch; i_ker_ch++)
1178→                                {
1179→                                    int32_t i_input_ch = i_group * ker_ch + i_ker_ch;
1180→                                    int32_t in_idx = (in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_input_ch;
1181→                                    int32_t wt_idx = i_out_ch * ker_ch * ker_dim_y * ker_dim_x + (i_ker_y * ker_dim_x + i_ker_x) * ker_ch + i_ker_ch;
1182→                                    int32_t in_val = in_tensor[in_idx] + in_offset;
1183→                                    int32_t wt_val = ker_weight[wt_idx];
1184→                                    conv_out += in_val * wt_val;
1185→                                }
1186→                            }
1187→                        }
1188→                        conv_out = nn_requantize(conv_out, out_scale[i_out_ch], out_shift[i_out_ch]);
1189→                        conv_out += out_offset;
1190→                        conv_out = MAX(conv_out, act_min);
1191→                        conv_out = MIN(conv_out, act_max);
1192→                        out_tensor[i_out_ch + (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch] = (int8_t)conv_out;
1193→                    }
1194→                }
1195→            }
1196→        }
1197→        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
1198→        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
1199→    }
1200→#endif  //ENA_EMPTY_FUN
1201→
1202→    /* Return to application */
1203→    return 0;
1204→}
1205→
1206→int32_t riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any_dilated_get_buffer_size(const uint16_t ker_ch,
1207→                                                                         const uint16_t ker_dim_x,
1208→                                                                         const uint16_t ker_dim_y,
1209→                                                                         const uint16_t out_tensor_ch)
1210→{
1211→#if defined(ENA_DSP_ISA_V5) || (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD))
1212→    const long align_byte = sizeof(long);
1213→
1214→    // four col buffer (supports 4-pixel batching for groups==1 unroll4 path)
1215→    int32_t buf_size = 4 * ker_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
1216→    buf_size += align_byte - 1;     //extra size for aligning
1217→
1218→    // buffer for extra contribution
1219→    buf_size += out_tensor_ch * sizeof(int32_t);
1220→    buf_size += align_byte - 1;     //extra size for aligning
1221→
1222→    return buf_size;
1223→#else
1224→    (void)ker_ch;
1225→    (void)ker_dim_x;
1226→    (void)ker_dim_y;
1227→    (void)out_tensor_ch;
1228→    return 0;
1229→#endif
1230→}
